CREATE VIEW "public"."vw_servicos" AS (SELECT (((date_part('year'::text, v.data_finaliza) || '/'::text) || "right"('0'::text || date_part('month'::text, v.data_finaliza), 2)))::character varying(7) AS anomes_fat, emp.emp_codigo, emp.emp_nomefantasia, emp.emp_sigla, (((date_part('year'::text, v.ven_data) || '/'::text) || "right"('0'::text || date_part('month'::text, v.ven_data), 2)))::character varying(7) AS anomes_emi, date_part('year'::text, v.ven_data)::character(4) AS ano_emi, date_part('year'::text, v.data_finaliza)::character(4) AS ano_fat, v.ven_status AS tipo, v.ven_status AS operacao_pedido, CASE WHEN v.ven_status = 'V'::bpchar THEN 'VENDA'::character varying(16) WHEN v.ven_status = 'F'::bpchar THEN 'VENDA A ENTREGAR'::character varying(16) WHEN v.ven_status = 'D'::bpchar THEN 'DEVOLUCAO'::character varying(16) WHEN v.ven_status = 'T'::bpchar THEN 'TROCA'::character varying(16) WHEN v.ven_status = 'B'::bpchar THEN 'BONIFICACAO'::character varying(16) WHEN v.ven_status = 'C'::bpchar THEN 'CONSIGNACAO'::character varying(16) WHEN v.ven_status = 'R'::bpchar THEN 'REMESSA'::character varying(16) WHEN v.ven_status = 'P'::bpchar THEN 'A PRODUZIR'::character varying(16) ELSE ''::character varying END AS tipo_descricao, v.ven_placa AS placa, v.ven_km AS km, v.tp_codigo AS cod_tipo_pgto, v.par_cp_codigo AS cod_condicao_pgto, v.ta_codigo AS cod_tabela_preco, tp.tp_descricao AS tipo_pgto, NULL::character varying(32) AS tamanho, ep.est_codigo AS cod_estado, ep.est_descricao AS estado, ve.ve_codigo AS cod_vendedor, f.fu_nome AS vendedor, f.fu_codigo, ff.fu_codigo AS fu_codigo_servico, (((ff.fu_nome::text || ' - '::text) || ff.fu_codigo))::character varying(77) AS func_servico, (((f.fu_nome::text || ' - '::text) || ve.ve_codigo))::character varying(77) AS vend, c.cli_codigo AS cod_cliente, c.cli_nome AS cliente, (((c.cli_nome::text || ' - '::text) || c.cli_codigo))::character varying(77) AS cli, c.cli_tipo AS tipo_cliente, sc.sgc_descricao AS segmento, c.sgc_codigo AS cod_segmento, gc.grc_descricao AS grupo_clientes, c.grc_codigo AS cod_grupo_clientes, e.descricao AS uf, c.cli_cidade AS cidade, rg.re_descricao AS regiao, c.reg_codigo, v.ven_cod_pedido AS pedido, NULL::character varying(7) AS modelo_dfe, NULL::character varying(20) AS numero_dfe, NULL::character varying(20) AS serie_dfe, v.ven_dfe AS dfe, v.ven_data AS dataemissao, v.ven_hora AS horaemissao, v.data_finaliza AS datafatura, v.ven_num_senha AS numerosenha, v.ven_tipo AS entrega, v.est_codigo AS faturado, v.finalizado, i.ser_codigo AS cod_servico, i.descricao AS descricao_ser, COALESCE(i.ser_valor_liquido, i.valor_unit)::numeric(18,2) AS servico, COALESCE(i.valor_bruto, 0::numeric)::numeric(18,2) AS valor_bruto, COALESCE(i.comissao_func, 0::numeric)::numeric(18,2) AS comissao_func, pc.n1, pc.n2, pc.n3, pc.n4, pc.co_codigo AS cod_plano, (((pc.co_estrutura::text || ' - '::text) || pc.co_descricao::text))::character varying(77) AS plano, pc.co_estrutura AS estrutura, v.cc_codigo AS cod_centrocusto, CASE WHEN COALESCE(v.cc_codigo, 0) <> 0 THEN ( SELECT cc.cc_descricao FROM centrocusto cc WHERE cc.cc_codigo = v.cc_codigo) ELSE ''::character varying END::character varying(250) AS centrocusto, (((COALESCE(i.valor_desc, 0::numeric) + COALESCE(i.ser_desc_rat, 0::numeric)) * v.ven_multiplicador::numeric)::numeric(18,2) * COALESCE(v.ven_cotacao_origem, 1::numeric)::numeric(18,4))::numeric(18,2) AS desconto, ((i.valor_desc * v.ven_multiplicador::numeric)::numeric(18,2) * COALESCE(v.ven_cotacao_origem, 1::numeric)::numeric(18,4))::numeric(18,2) AS desconto_produto, (i.ser_desc_rat * v.ven_multiplicador::numeric * COALESCE(v.ven_cotacao_origem, 1::numeric)::numeric(18,4))::double precision AS desconto_pedido, replace(v.ven_obs, ascii_char(13)::text || ascii_char(10)::text, ' '::text)::character varying(2000) AS obs, c.cli_nome_fantasia AS nome_fantasia, c.cli_endereco AS endereco, c.cli_cep AS cep, c.cli_bairro AS bairro, c.cli_complemento AS complemento, c.cli_telefone AS telefone, c.cli_cnpj_cpf AS cnpj_cpf, co.par_descricao AS cond_pagto, t.ta_descricao AS tabela_preco, v.ven_aplicacao AS aplicacao, v.ven_comprador AS comprador, (((COALESCE(ebc.bc_endereco, ''::character varying)::text || ', '::text) || COALESCE(ebc.bc_numero, ''::character varying)::text))::character varying(77) AS entrega_endereco, COALESCE(ebc.bc_bairro, ''::character varying)::character varying(32) AS entrega_bairro, COALESCE(ebc.bc_cep, ''::character varying)::character varying(10) AS entrega_cep, COALESCE(ebc.bc_complemento, ''::character varying)::character varying(64) AS entrega_complemento, COALESCE(eci.ci_descricao, ''::character varying)::character varying(64) AS entrega_cidade, COALESCE(est.descricao, ''::bpchar)::character varying(2) AS entrega_estado, v.ven_modelo_venda AS modelo_venda, v.ven_modelo_venda_desc AS modelo_venda_desc, i.descricao::character varying(64) AS descricao_ser_v64, c.ve_codigo AS cod_vendedor_cliente, v.tx_codigo AS cod_caixa, gre.gre_codigo AS cod_grupo_economico_cliente, gre.gre_descricao AS desc_grupo_economico_cliente, v.elc_codigo AS cod_local_estoque, elc.elc_descricao AS local_estoque, usu.usu_login, ts.ts_codigo, ts.descricao AS tipo_servico, c.cli_celular, c.cli_fax FROM vendas v JOIN itens_servico i ON i.ven_cod_pedido = v.ven_cod_pedido JOIN plano_contas pc ON pc.co_codigo = v.co_codigo JOIN estado_pedido ep ON ep.est_codigo = v.est_codigo JOIN clientes c ON c.cli_codigo = v.cli_codigo LEFT JOIN segmento_cliente sc ON sc.sgc_codigo = c.sgc_codigo LEFT JOIN grupo_cliente gc ON gc.grc_codigo = c.grc_codigo LEFT JOIN regiao rg ON rg.re_codigo = c.reg_codigo LEFT JOIN empresa emp ON emp.emp_codigo = v.emp_codigo JOIN estado e ON e.es_codigo = c.es_codigo JOIN vendedor ve ON ve.ve_codigo = v.ve_codigo JOIN funcionario f ON f.fu_codigo = ve.fu_codigo JOIN funcionario ff ON ff.fu_codigo = i.fu_codigo LEFT JOIN tipo_pagamento tp ON tp.tp_codigo = v.tp_codigo LEFT JOIN condicao_pagto co ON co.par_cp_codigo = v.par_cp_codigo LEFT JOIN tab