CREATE VIEW "public"."vw_hist_alt_para_alt_terminal" AS (SELECT h.ha_codigo, r.tx_codigo, h.ha_schema AS at_schema, h.ha_tabela AS at_tabela, CURRENT_TIMESTAMP AS at_data_inclusao, NULL::text AS at_data_processamento, h.ha_acao AS at_acao, h.ha_pks AS at_pks, h.ha_modificado AS at_modificado, true AS fila_normal FROM historico_alteracoes h JOIN replicar_alteracoes_terminal r ON r.ha_codigo = h.ha_codigo AND r.rat_inicio_sinc IS NULL UNION SELECT alteracoes_dfe_sinc_off.adso_codigo AS ha_codigo, alteracoes_dfe_sinc_off.tx_codigo, alteracoes_dfe_sinc_off.adso_schema AS at_schema, alteracoes_dfe_sinc_off.adso_tabela AS at_tabela, CURRENT_TIMESTAMP AS at_data_inclusao, NULL::text AS at_data_processamento, 'U'::text AS at_acao, alteracoes_dfe_sinc_off.adso_pk AS at_pks, alteracoes_dfe_sinc_off.adso_json_alteracao AS at_modificado, false AS fila_normal FROM alteracoes_dfe_sinc_off WHERE alteracoes_dfe_sinc_off.adso_inicio_sinc IS NULL);--> statement-breakpoint
CREATE VIEW "public"."vw_preco_venda_x_pdv_offline" AS (SELECT pv.pvo_codigo, pv.pro_codigo, pv.tx_codigo, pv.pvo_status, pv.pvo_dh_att_agendada, pv.pvo_sincronizado, pv.da, pv.di, pd.pro_descricao, pd.pro_preco_venda FROM preco_venda_x_pdv_offline pv JOIN produto pd ON pd.pro_codigo = pv.pro_codigo ORDER BY ( CASE WHEN pv.pvo_status = 'I'::bpchar THEN 1 WHEN pv.pvo_status = 'L'::bpchar THEN 2 WHEN pv.pvo_status = 'A'::bpchar THEN 3 ELSE 4 END));--> statement-breakpoint
CREATE VIEW "public"."vw_cartao_x_credenciadora_empresa" AS (SELECT c.car_codigo, c.car_bandeira, c.car_tipo, c.car_forma_pagto_cfe, c.tp_codigo, c.car_band_nfe, c.cmp_codigo_old, c.car_tipo_taxa, c.car_valor_taxa, c.co_codigo_taxa, c.cb_codigo, c.car_status, c.id_destino, ce.cmp_codigo, ce.emp_codigo FROM cartao c JOIN cartao_empresa ce ON ce.car_codigo = c.car_codigo);--> statement-breakpoint
CREATE VIEW "public"."vw_dependencias_pk" AS (SELECT tc.constraint_name AS nome_constraint, tc.table_name, kcu.column_name, ccu.table_name AS foreign_table_name, ccu.column_name AS foreign_column_name FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON kcu.constraint_name::name = tc.constraint_name::name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_name::name = tc.constraint_name::name WHERE tc.constraint_type::text = 'FOREIGN KEY'::text);--> statement-breakpoint
CREATE VIEW "public"."vw_tab_preco_itens_x_pdv_offline" AS (SELECT tp.pip_codigo, tp.pro_codigo, tp.ta_codigo, tp.tpi_codigo, tp.tx_codigo, tp.pip_status, tp.pip_operacao, tp.pip_dh_att_agendada, tp.pip_sincronizado, tp.da, tp.di, ti.tpi_preco, ti.tpi_margem_aplicada, ti.tpi_tipo, p.pro_descricao, ta.ta_descricao FROM tab_preco_itens_x_pdv_offline tp JOIN tabela_preco_itens ti ON ti.tpi_codigo = tp.tpi_codigo JOIN produto p ON p.pro_codigo = ti.pro_codigo JOIN tabela_preco ta ON ta.ta_codigo = ti.ta_codigo ORDER BY ( CASE WHEN tp.pip_operacao = 'I'::bpchar THEN 1 ELSE 2 END), ( CASE WHEN tp.pip_status = 'I'::bpchar THEN 1 WHEN tp.pip_status = 'L'::bpchar THEN 2 WHEN tp.pip_status = 'A'::bpchar THEN 3 ELSE 4 END));--> statement-breakpoint
CREATE VIEW "public"."vw_hist_alt_preco_produto" AS (SELECT historico_log.hl_data AS data_alteracao, historico_log.hl_hora AS hora_alteracao, historico_log.pro_codigo, replace(replace(historico_log.hl_depois::text, '.'::text, ''::text), ','::text, '.'::text)::numeric(19,4) AS preco_alterado, historico_log.hl_campo AS historico_descricao FROM historico_log WHERE upper(historico_log.hl_campo::text) ~~ '%PRE_O%VENDA%'::text AND historico_log.hl_tabela::text = 'PRODUTO'::text AND COALESCE(historico_log.hl_depois, ''::character varying)::text <> ''::text ORDER BY historico_log.hl_data DESC, historico_log.hl_hora DESC);--> statement-breakpoint
CREATE VIEW "public"."vw_margem_bruta_proporcional" AS (WITH totais_venda AS ( SELECT itens_venda.ven_cod_pedido, sum(itens_venda.ite_total_pedido) AS total_venda, sum(itens_venda.ite_valor_custo::double precision * itens_venda.ite_qtd) AS total_custo FROM itens_venda GROUP BY itens_venda.ven_cod_pedido ), custo_parcela AS ( SELECT t.ven_cod_pedido, t.total_custo / NULLIF(count(1), 0)::double precision AS custo_parcela FROM contas_receber cr JOIN totais_venda t ON t.ven_cod_pedido = cr.ven_cod_pedido GROUP BY t.total_custo, t.ven_cod_pedido ), parcelas AS ( SELECT cr.cr_codigo, cr.ven_cod_pedido, cr.cr_data_emissao, cr.cr_acrecimo, cr.cr_abatimento, cr.cr_valor_parcela + cr.cr_acrecimo - cr.cr_abatimento AS valor_parcela, cr.cr_num_parcela FROM contas_receber cr ), base AS ( SELECT p.cr_data_emissao, p.cr_codigo, i.ven_cod_pedido, c.cli_codigo, c.cli_nome, c.cli_cnpj_cpf, p.cr_num_parcela, i.pro_codigo, i.ite_descricao, i.ite_total_pedido, i.ite_valor_custo::double precision * i.ite_qtd AS ite_valor_custo, p.cr_acrecimo * i.ite_total_pedido / NULLIF(t.total_venda, 0::numeric) AS cr_acresc_proporcional, p.cr_abatimento * i.ite_total_pedido / NULLIF(t.total_venda, 0::numeric) AS cr_desc_proporcional, p.valor_parcela, cp.custo_parcela, t.total_venda, p.valor_parcela * (i.ite_total_pedido / NULLIF(t.total_venda, 0::numeric)) AS valor_proporcional, cp.custo_parcela * (i.ite_total_pedido / NULLIF(t.total_venda, 0::numeric))::double precision AS custo_proporcional, (p.valor_parcela::double precision - cp.custo_parcela) / NULLIF(p.valor_parcela, 0::numeric)::double precision AS margem_parcela_pct FROM itens_venda i JOIN totais_venda t ON i.ven_cod_pedido = t.ven_cod_pedido JOIN parcelas p ON p.ven_cod_pedido = i.ven_cod_pedido JOIN custo_parcela cp ON cp.ven_cod_pedido = i.ven_cod_pedido JOIN vendas v ON v.ven_cod_pedido = i.ven_cod_pedido JOIN clientes c ON c.cli_codigo = v.cli_codigo ) SELECT base.ven_cod_pedido AS cod_venda, base.cr_data_emissao AS data_emissao_parcela, base.cli_codigo AS cod_cliente, base.cli_nome AS nome, base.cli_cnpj_cpf AS cnpj_cpf, base.cr_codigo AS cod_parcela, base.cr_num_parcela AS num_parcela, base.pro_codigo AS cod_produto, base.ite_descricao AS produto, base.ite_total_pedido::numeric(19,2) AS valor_total_item, base.ite_valor_custo::numeric(19,2) AS custo_total_item, (base.ite_total_pedido::double precision - base.ite_valor_custo)::numeric(19,2) AS margem_bruta_original, base.cr_acresc_proporcional::numeric(19,2) AS acrescimo_proporcional, base.cr_desc_proporcional::numeric(19,2) AS desconto_proporcional, base.valor_proporcional::numeric(19,2) AS valor_proporcional, base.custo_proporcional::numeric(19,2) AS custo_proporcional, (base.valor_proporcional::double precision - base.custo_proporcional)::numeric(19,2) AS margem_bruta_proporcional, (base.margem_parcela_pct * (base.ite_total_pedido / NULLIF(base.total_venda, 0::numeric))::double precision * 100::double precision)::numeric(19,3) AS margem_bruta_perc_proporcional FROM base);--> statement-breakpoint
CREATE VIEW "public"."vw_etiqueta" AS (SELECT e.pro_descricao, e.pro_preco_venda, e.pro_referencia, e.pro_preco_vista, e.pro_tamanho, e.pro_cor, e.pro_parcela, e.pro_valor_parcela, e.pro_codigo_or, e.pro_codigo_ordem, e.ite_data_ordem, e.pro_parcela_dois, e.pro_valor_parcela_dois, e.pro_preco_venda_dois, e.preco_custo_oculto, e.data_compra, m.ma_descricao AS marca, p.pro_colecao, p.pro_linha, g.grp_descricao AS grupo, s.sub_descricao AS subgrupo, CASE WHEN COALESCE(p.dep_codigo, 0) <> 0 THEN ( SELECT d.dep_descricao FROM departamento d WHERE p.dep_codigo = d.dep_codigo) ELSE ''::character varying END::character varying(64) AS departamento FROM etiqueta e JOIN produto p ON p.pro_codigo_or::text = e.pro_codigo_or::text JOIN marca m ON m.ma_codigo = p.ma_codigo JOIN grupos g ON g.grp_codigo = p.grp_codigo JOIN sub_grupo s ON s.sub_codigo = p.sub_codigo AND s.grp_codigo = g.grp_codigo);--> statement-breakpoint
CREATE VIEW "public"."vw_integracao_juntos_somos_mais" AS (WITH ultima_compra_produto AS ( SELECT max(ic.cmp_codigo) AS ultima_compra, ic.pro_codigo FROM itens_compra ic GROUP BY ic.pro_codigo ) SELECT v.ven_cod_pedido::character varying(20) AS number_identifier, v.ven_data AS purchase_date, iv.ite_total_bruto::numeric(18,4) AS total_price, stp_somente_numeros_letras(emp.emp_cnpj)::character varying(14) AS store_cnpj, NULL::character varying(20) AS operator_identifier, NULL::character varying(14) AS operator_cpf, f2.fu_nome::character varying(20) AS seller_identifier, stp_somente_numeros_letras(f2.fu_cpf)::character varying(14) AS seller_cpf, c.cli_nome::character varying(20) AS professional_identifier, stp_somente_numeros_letras(c.cli_cnpj_cpf)::character varying(14) AS professional_cpf, p.pro_descricao::character varying(60) AS description, iv.ite_qtd_up::numeric(18,0) AS quantity, iv.ite_valor_unit::numeric(18,4) AS unit_price, NULL::numeric(18,0) AS points, COALESCE(f.for_nome, 'SEM FORNECEDOR'::character varying)::character varying(100) AS ad_supplier, NULL::character varying(20) AS ad_seller_identifier, NULL::character varying(14) AS ad_seller_cpf FROM vendas v LEFT JOIN vendedor v2 ON v2.ve_codigo = v.ve_codigo LEFT JOIN funcionario f2 ON f2.fu_codigo = v2.fu_codigo JOIN itens_venda iv ON iv.ven_cod_pedido = v.ven_cod_pedido JOIN empresa emp ON emp.emp_codigo = v.emp_codigo JOIN parametro pr ON pr.emp_codigo = emp.emp_codigo JOIN produto p ON p.pro_codigo = iv.pro_codigo JOIN clientes c ON c.cli_codigo = v.cli_codigo AND c.cli_codigo <> pr.consumidor_padrao AND COALESCE(c.cli_cnpj_cpf, ''::character varying)::text <> ''::text LEFT JOIN ultima_compra_produto ucp ON ucp.pro_codigo = iv.pro_codigo LEFT JOIN compra cmp ON cmp.cmp_codigo = ucp.ultima_compra LEFT JOIN fornecedor f ON f.for_codigo = cmp.for_codigo);--> statement-breakpoint
CREATE VIEW "public"."vw_classificacao_fiscal" AS (SELECT CASE WHEN cf.cl_vigencia_inicial IS NULL AND cf.cl_vigencia_final IS NULL OR cf.cl_vigencia_inicial IS NULL AND cf.cl_vigencia_final IS NOT NULL AND CURRENT_DATE <= cf.cl_vigencia_final OR cf.cl_vigencia_inicial IS NOT NULL AND cf.cl_vigencia_final IS NOT NULL AND CURRENT_DATE >= cf.cl_vigencia_inicial AND CURRENT_DATE <= cf.cl_vigencia_final OR cf.cl_vigencia_inicial IS NOT NULL AND cf.cl_vigencia_final IS NULL AND CURRENT_DATE >= cf.cl_vigencia_inicial THEN 'V'::text WHEN cf.cl_vigencia_inicial IS NULL AND cf.cl_vigencia_final IS NOT NULL AND CURRENT_DATE > cf.cl_vigencia_final OR cf.cl_vigencia_inicial IS NOT NULL AND cf.cl_vigencia_final IS NOT NULL AND CURRENT_DATE > cf.cl_vigencia_final THEN 'E'::text ELSE 'F'::text END::character(1) AS status, CASE WHEN cf.nc_codigo IS NOT NULL AND cf.es_codigo IS NOT NULL THEN 1 WHEN cf.nc_codigo IS NOT NULL AND cf.cl_id_dest IS NOT NULL AND cf.es_codigo IS NULL THEN 2 WHEN cf.agf_codigo IS NOT NULL AND cf.es_codigo IS NOT NULL THEN 3 WHEN cf.agf_codigo IS NOT NULL AND cf.cl_id_dest IS NOT NULL AND cf.es_codigo IS NULL THEN 4 ELSE NULL::integer END AS prioridade, cf.cl_codigo, cf.tf_codigo, cf.es_codigo, cf.to_codigo, cf.no_codigo, cf.cs_codigo, cf.nm_codigo, cf.ic_codigo, cf.base_ipi, cf.alicota_ipi, cf.ipi_icms, cf.base_calculo, cf.reducao_base_calculo, cf.alicota_icms, cf.st_base_calculo, cf.st_alicota, cf.pis_alicota, cf.cofins_alicota, cf.nc_codigo, cf.tipo_prod, cf.cst_ipi, cf.cst_pis, cf.cst_cofins, cf.cs_mod_bc, cf.cs_mod_bcst, cf.cs_pmvast, cf.cs_predbcst, cf.base_retprevsoc, cf.valor_retprevsoc, cf.icms_interno, cf.icms_interestadual, cf.aliquota_deducao_simples, cf.base_pis, cf.base_cofins, cf.regime_trib, cf.es_codigo_icms_st, cf.bc_st_uf_remetente, cf.icms_st_uf_remetente, cf.bc_st_uf_destino, cf.icms_st_uf_destino, cf.mot_codigo, cf.aliquota_ajust_interestadual, cf.tipo_prod_serv, cf.bc_irrf, cf.alicota_irrf, cf.bc_csll, cf.alicota_csll, cf.exc_codigo, cf.bc_desoneracao_icms, cf.aliq_desoneracao_icms, cf.aliquota_fcp_uf_dest, cf.bc_icms_uf_dest, cf.eipi_codigo, cf.perc_dif_icms, cf.bc_ii, cf.alq_ii, cf.ts_codigo, cf.exigibilidade_issqn, cf.incluir_ii_bcipi, cf.bc_icmsst_ret, cf.aliquota_icmsst_ret, cf.percentual_outras_despesas, cf.aliquota_fcp_interno, cf.reducao_bc_efetiva, cf.base_calculo_efetiva, cf.alicota_icms_efetiva, cf.aliquota_icms_proprio_sub, cf.cl_padrao, cf.cl_deduzir_frete_bc_icms, cf.emp_codigo, cf.cl_credicmssn_calcular, cf.cl_credicmssn_reducao_bc, cf.cl_credicmssn_bc, cf.mot_codigo_st, cf.bc_desoneracao_icms_st, cf.aliq_desoneracao_icms_st, cf.cl_excluir_icms_bc_pis_cofins, cf.cl_cod_benef, cf.agf_codigo, cf.cl_id_dest, cf.cl_vigencia_inicial, cf.cl_vigencia_final, cf.id_destino, cf.class_saneamento_fiscal_att, cf.atualizar_dados_via_imendes, cf.criado_via_imendes, cf.ultima_revisao_imendes, cf.criado_via_geracao_class_base, cf.class_processada_intel_fis, cf.aliquota_icms_proprio_desc_st, cf.cl_excluir_icmsst_bc_pis_cofins, cf.cl_utiliza_pauta, cf.agf_codigo IS NOT NULL AS origem_agrupador, cf.nc_codigo IS NOT NULL AS origem_ncm FROM classificacao_fiscal cf ORDER BY ( CASE WHEN cf.nc_codigo IS NOT NULL AND cf.es_codigo IS NOT NULL THEN 1 WHEN cf.nc_codigo IS NOT NULL AND cf.cl_id_dest IS NOT NULL AND cf.es_codigo IS NULL THEN 2 WHEN cf.agf_codigo IS NOT NULL AND cf.es_codigo IS NOT NULL THEN 3 WHEN cf.agf_codigo IS NOT NULL AND cf.cl_id_dest IS NOT NULL AND cf.es_codigo IS NULL THEN 4 ELSE NULL::integer END), ( CASE WHEN cf.cl_vigencia_inicial IS NULL AND cf.cl_vigencia_final IS NULL OR cf.cl_vigencia_inicial IS NULL AND cf.cl_vigencia_final IS NOT NULL AND CURRENT_DATE <= cf.cl_vigencia_final OR cf.cl_vigencia_inicial IS NOT NULL AND cf.cl_vigencia_final IS NOT NULL AND CURRENT_DATE >= cf.cl_vigencia_inicial AND CURRENT_DATE <= cf.cl_vigencia_final OR cf.cl_vigencia_inicial IS NOT NULL AND cf.cl_vigencia_final IS NULL AND CURRENT_DATE >= cf.cl_vigencia_inicial THEN 'V'::text WHEN cf.cl_vigencia_inicial IS NULL AND cf.cl_vigencia_final IS NOT NULL AND CURRENT_DATE > cf.cl_vigencia_final OR cf.cl_vigencia_inicial IS NOT NULL AND cf.cl_vigencia_final IS NOT NULL AND CURRENT_DATE > cf.cl_vigencia_final THEN 'E'::text ELSE 'F'::text END::character(1)) DESC);--> statement-breakpoint
CREATE VIEW "public"."vw_plano_contas" AS (SELECT (((p1.co_estrutura::text || ' - '::text) || p1.co_descricao::text))::character varying(77) AS nivel_1, (((p2.co_estrutura::text || ' - '::text) || p2.co_descricao::text))::character varying(77) AS nivel_2, (((p3.co_estrutura::text || ' - '::text) || p3.co_descricao::text))::character varying(77) AS nivel_3, (((p4.co_estrutura::text || ' - '::text) || p4.co_descricao::text))::character varying(77) AS nivel_4, p4.co_codigo, p4.co_estrutura, p4.co_descricao, p4.n1, p4.n2, p4.n3, p4.n4, e.emp_codigo FROM empresa e, plano_contas p1, plano_contas p2, plano_contas p3, plano_contas p4 WHERE p1.emp_codigo = e.emp_codigo AND p2.emp_codigo = e.emp_codigo AND p3.emp_codigo = e.emp_codigo AND p4.emp_codigo = e.emp_codigo AND p1.n1 = p2.n1 AND p1.n1 = p3.n1 AND p2.n2 = p3.n2 AND p1.n1 = p4.n1 AND p1.n2 = 0 AND p1.n3 = 0 AND p1.n4 = 0 AND p2.n2 = p4.n2 AND p2.n3 = 0 AND p2.n4 = 0 AND p3.n3 = p4.n3 AND p3.n4 = 0);--> statement-breakpoint
CREATE VIEW "public"."vw_promocoes_grupo" AS (SELECT promocoes_grupo.prg_codigo, promocoes_grupo.prg_descricao, promocoes_grupo.prg_data_inicial, promocoes_grupo.prg_data_final, promocoes_grupo.prg_criado_via_scanntech, CASE WHEN CURRENT_DATE > promocoes_grupo.prg_data_final THEN 0 WHEN CURRENT_DATE >= promocoes_grupo.prg_data_inicial AND CURRENT_DATE <= promocoes_grupo.prg_data_final THEN 1 WHEN CURRENT_DATE < promocoes_grupo.prg_data_inicial THEN 2 ELSE NULL::integer END AS prg_status, CASE WHEN CURRENT_DATE > promocoes_grupo.prg_data_final THEN 'Expirada'::text WHEN CURRENT_DATE >= promocoes_grupo.prg_data_inicial AND CURRENT_DATE <= promocoes_grupo.prg_data_final THEN 'Em Vigor'::text WHEN CURRENT_DATE < promocoes_grupo.prg_data_inicial THEN 'Futura'::text ELSE NULL::text END AS prg_status_desc FROM promocoes_grupo);--> statement-breakpoint
CREATE VIEW "public"."vw_email_cliente_assinatura" AS (SELECT c.cli_codigo AS cod_cliente, string_agg(c.con_email::text, ' '::text) AS email_assinados, ca.ass_codigo AS cod_assinatura, a.ass_descricao AS descricao_assinatura, c.con_status FROM contatos c JOIN contato_assinaturas ca ON ca.con_codigo = c.con_codigo JOIN assinaturas a ON a.ass_codigo = ca.ass_codigo GROUP BY c.cli_codigo, ca.ass_codigo, a.ass_descricao, c.con_status;);--> statement-breakpoint
CREATE VIEW "public"."vw_tabela_preco" AS (WITH produtos AS ( SELECT emp.emp_codigo, p_1.pro_codigo, p_1.pro_bloqueio_old, p_1.pro_unidade, p_1.pro_preco_venda, p_1.pro_peso_bruto, p_1.pro_peso, p_1.pro_preco_custo::numeric(18,4) AS pro_preco_custo, p_1.pro_desconto_max, p_1.pro_acrescimo_max_app, p_1.pro_qtd_embalagem, p_1.pro_multiplos_por_embalagem, p_1.un_codigo_embalagem, u3.un_descricao AS pro_unidade_embalagem, ARRAY[1.00::double precision, COALESCE(p_1.pro_peso_bruto, 0.00::real)::double precision, COALESCE(p_1.pro_peso, 0.00::real)::double precision] AS array_peso, iif(pa.app_tipo_codigo = 'B'::character(1), p_1.pro_codigo_or, p_1.pro_codigo::character varying(10)) AS pro_codigo_app, p_1.pro_descricao, p_1.pro_venda_app, p_1.da_tabela_preco AS pro_da_tabela_preco, iif(COALESCE(p_1.pro_segunda_unidade, ''::character varying)::text = ''::text OR p_1.pro_unidade_app = 'UP'::character(2), p_1.pro_unidade, p_1.pro_segunda_unidade) AS pro_unidade_app, iif(p_1.pro_fator_conversao = 0::numeric OR p_1.pro_unidade_app = 'UP'::character(2), 1.0, p_1.pro_fator_conversao) AS pro_fator_conversao_app, u.un_fracao, iif(p_1.pro_unidade_app = 'UP'::bpchar, u.un_descricao, COALESCE(u2.un_descricao, u.un_descricao)) AS unidade_app, iif(p_1.pro_unidade_app = 'UP'::bpchar, u.un_fracao, COALESCE(u2.un_fracao, u.un_fracao)) AS fracao_app FROM produto p_1 JOIN empresa emp ON true JOIN parametro pa ON pa.emp_codigo = emp.emp_codigo JOIN unidade u ON u.un_descricao::character varying(12)::text = p_1.pro_unidade::character varying(12)::text LEFT JOIN unidade u2 ON u2.un_descricao::character varying(12)::text = p_1.pro_segunda_unidade::character varying(12)::text AND p_1.pro_unidade::character varying(12)::text <> p_1.pro_segunda_unidade::character varying(12)::text AND COALESCE(p_1.pro_segunda_unidade, ''::character varying)::character varying(12)::text <> ''::character varying(12)::text LEFT JOIN unidade u3 ON u3.un_codigo = p_1.un_codigo_embalagem ) SELECT p.pro_codigo, t.ta_codigo,