unidade_app, p.fracao_app, (iif(t.ta_valor_base = 0, p.pro_preco_venda, p.pro_preco_custo)::double precision - p.array_peso[t.ta_opcao_valor_desconto + 1] * t.ta_valor_desc + p.array_peso[t.ta_opcao_valor_acrescimo + 1] * t.ta_valor_acre - iif(t.ta_valor_base = 0, p.pro_preco_venda, p.pro_preco_custo)::double precision * (t.ta_desconto / 100::double precision) * p.array_peso[t.ta_opcao_percentual_desconto + 1] + iif(t.ta_valor_base = 0, p.pro_preco_venda, p.pro_preco_custo)::double precision * (t.ta_acrecimo / 100::double precision) * p.array_peso[t.ta_opcao_percentual_acrescimo + 1])::numeric(18,4) AS preco_com_base_na_tabela FROM produtos p JOIN tabela_preco t ON true LEFT JOIN tabela_preco_itens i ON i.ta_codigo = t.ta_codigo AND i.pro_codigo = p.pro_codigo LEFT JOIN excecao_tabela_preco e ON e.pro_codigo = p.pro_codigo AND e.ta_codigo = t.ta_codigo JOIN estoque_empresa_saldo ees ON ees.emp_codigo = p.emp_codigo AND ees.pro_codigo = p.pro_codigo);--> statement-breakpoint
CREATE VIEW "public"."vw_etiqueta_peso" AS (SELECT p.pro_codigo, p.pro_codigo_or, p.pro_descricao, p.pro_unidade, e.er_peso, e.for_codigo, COALESCE(f.for_nome, ''::character varying(64)) AS for_nome, e.er_nota, e.er_data, COALESCE(m.ma_descricao, ''::character varying(64)) AS ma_descricao, p.pro_cor, p.pro_composicao, p.pro_tamanho AS pro_tamamho FROM etiqueta_rolo e JOIN produto p ON p.pro_codigo = e.pro_codigo LEFT JOIN fornecedor f ON f.for_codigo = e.for_codigo LEFT JOIN marca m ON m.ma_codigo = p.ma_codigo);--> statement-breakpoint
CREATE VIEW "public"."vw_tabela_preco_demander" AS (WITH produto_x_tabelapreco AS ( SELECT p.pro_codigo, t.ta_codigo, p.da_tabela_preco, GREATEST(p.da, ua.da) AS da_ua, datediff('MINUTE'::character varying, p.da_tabela_preco, LOCALTIMESTAMP) >= 3 AND datediff('MINUTE'::character varying, p.da_tabela_preco, LOCALTIMESTAMP) <= 13 AS diferenca FROM produto p JOIN tabela_preco t ON true LEFT JOIN unidades_alternativas ua ON ua.pro_codigo = p.pro_codigo WHERE p.pro_venda_app = ANY (ARRAY['Y'::bpchar, 'I'::bpchar]) ), produtos_promocao AS ( SELECT pp_1.pro_codigo, prm.prm_preco_promocao, prg.prg_data_inicial, prg.prg_data_final FROM promocoes_produtos pp_1 JOIN produto pa_1 ON pp_1.pro_codigo = pa_1.pro_codigo AND (pa_1.pro_venda_app = ANY (ARRAY['Y'::bpchar, 'I'::bpchar])) JOIN promocoes prm ON prm.prm_codigo = pp_1.prm_codigo JOIN promocoes_grupo prg ON prg.prg_codigo = prm.prg_codigo JOIN promocoes_grupo_x_empresa pge ON pge.prg_codigo = prg.prg_codigo AND pge.emp_codigo = (( SELECT empresa.emp_codigo FROM empresa WHERE empresa.emp_demander AND empresa.emp_ativa ORDER BY empresa.emp_codigo LIMIT 1)) WHERE pp_1.prp_tipo = 'P'::bpchar AND prm.prm_status = '1'::bpchar AND CURRENT_DATE >= prg.prg_data_inicial AND CURRENT_DATE <= prg.prg_data_final AND prm.prm_tipo = 0 AND prm.prm_exclusiva_meio_pagto = false ), produtos_tabelas_alterados AS ( SELECT p.pro_codigo, p.ta_codigo FROM produto_x_tabelapreco p LEFT JOIN produtos_promocao pp_1 ON pp_1.pro_codigo = p.pro_codigo LEFT JOIN ultima_sincronizacao_app_tabela_13 us ON us.usa_id = p.ta_codigo AND us.usa_id2 = p.pro_codigo WHERE us.usa_codigo IS NULL OR us.usa_dus IS NULL OR p.diferenca OR p.da_ua > COALESCE(us.usa_dus, p.da_ua) OR COALESCE(us.usa_dus, LOCALTIMESTAMP) <= pp_1.prg_data_inicial ), produtos_alterados AS ( SELECT DISTINCT produtos_tabelas_alterados.pro_codigo FROM produtos_tabelas_alterados ), empresa_demander AS ( SELECT empresa.emp_codigo FROM empresa WHERE empresa.emp_demander ORDER BY empresa.emp_codigo LIMIT 1 ), porc_un_alternativas AS ( SELECT ua.pro_codigo, sum(ua.una_porcentual_estoque_demander) AS total FROM unidades_alternativas ua JOIN produtos_alterados pa_1 ON pa_1.pro_codigo = ua.pro_codigo GROUP BY ua.pro_codigo ), produto_unidade_alternativa_demander AS ( SELECT ((p.pro_codigo::character varying::text || '.'::text) || ua.una_apelido::text)::character varying AS cod_produto, ua.pro_codigo, u.un_descricao AS unidade, ua.una_fator AS fator_un1, ua.una_fator AS fator_conversao, iif(u.un_fracao = 'D'::bpchar, 1, 0) AS decimal_fracao FROM unidades_alternativas ua JOIN produtos_alterados pra ON pra.pro_codigo = ua.pro_codigo JOIN produto p ON ua.pro_codigo = p.pro_codigo JOIN unidade u ON u.un_codigo = ua.un_codigo JOIN empresa_demander e ON true JOIN parametro pa_1 ON pa_1.emp_codigo = e.emp_codigo AND pa_1.app_tipo_codigo = 'I'::bpchar LEFT JOIN porc_un_alternativas pu ON pu.pro_codigo = p.pro_codigo UNION ALL SELECT iif(pa_1.app_tipo_codigo = 'B'::bpchar, p.pro_codigo_or, p.pro_codigo::character varying(20)) AS cod_produto, p.pro_codigo, iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar, p.pro_unidade, p.pro_segunda_unidade) AS unidade, iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar, 1::numeric(18,3), p.pro_fator_conversao) AS fator_un1, iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text, 1::numeric(18,3), p.pro_fator_conversao) AS fator_conversao, iif(u.un_fracao = 'D'::bpchar, 1, 0) AS decimal_fracao FROM produtos_alterados pra JOIN produto p ON p.pro_codigo = pra.pro_codigo JOIN empresa_demander e ON true JOIN unidade u ON u.un_descricao::text = iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar, p.pro_unidade, p.pro_segunda_unidade)::text LEFT JOIN porc_un_alternativas pu ON pu.pro_codigo = p.pro_codigo JOIN parametro pa_1 ON pa_1.emp_codigo = e.emp_codigo ), produtos AS ( SELECT emp.emp_codigo, p.pro_codigo, p.pro_bloqueio_old, p.pro_unidade, p.pro_preco_venda, p.pro_peso_bruto, p.pro_peso, p.pro_preco_custo::numeric(18,4) AS pro_preco_custo, p.pro_desconto_max, p.pro_acrescimo_max_app, p.pro_qtd_embalagem, p.pro_multiplos_por_embalagem, p.un_codigo_embalagem, u3.un_descricao AS pro_unidade_embalagem, ARRAY[1.00::double precision, COALESCE(p.pro_peso_bruto, 0.00::real)::double precision, COALESCE(p.pro_peso, 0.00::real)::double precision] AS array_peso FROM produto p JOIN empresa_demander emp ON true JOIN parametro pa_1 ON pa_1.emp_codigo = emp.emp_codigo JOIN unidade u ON u.un_descricao::character varying(12)::text = p.pro_unidade::character varying(12)::text LEFT JOIN unidade u2 ON u2.un_descricao::character varying(12)::text = p.pro_segunda_unidade::character varying(12)::text AND p.pro_unidade::character varying(12)::text <> p.pro_segunda_unidade::character varying(12)::text AND COALESCE(p.pro_segunda_unidade, ''::character varying)::character varying(12)::text <> ''::character varying(12)::text LEFT JOIN unidade u3 ON u3.un_codigo = p.un_codigo_embalagem ), tabela_preco_demander AS ( SELECT p.pro_codigo, px.pxe_bloqueio, t.ta_codigo, iif(e.pro_codigo IS NOT NULL, p.pro_preco_venda, COALESCE(i.tpi_preco, (iif(t.ta_valor_base = 0, p.pro_preco_venda, p.pro_preco_custo)::double precision - p.array_peso[t.ta_opcao_valor_desconto + 1] * t.ta_valor_desc + p.array_peso[t.ta_opcao_valor_acrescimo + 1] * t.ta_valor_acre - iif(t.ta_valor_base = 0, p.pro_preco_venda, p.pro_preco_custo)::double precision * (t.ta_desconto / 100::double precision) * p.array_peso[t.ta_opcao_percentual_desconto + 1] + iif(t.ta_valor_base = 0, p.pro_preco_venda, p.pro_preco_custo)::double precision * (t.ta_acrecimo / 100::double precision) * p.array_peso[t.ta_opcao_percentual_acrescimo + 1])::numeric(18,8)))::numeric(18,8) AS preco_da_tabela, t.ta_preco_travado, COALESCE(p.pro_peso_bruto, 0::real) AS pro_pes