nicial_promo, pp.prg_data_final AS data_final_promo, tp.preco_da_tabela > COALESCE(pp.prm_preco_promocao, 0.00) AND COALESCE(pp.prm_preco_promocao, 0.00) > 0.00 AND tp.ta_preco_promocional_demander = 'R'::bpchar AS utilizar_preco_promocional, tp.pro_qtd_embalagem, tp.pro_multiplos_por_embalagem, tp.pro_unidade_embalagem, pa.quebra_de_embalagem_demander FROM tabela_preco_demander tp JOIN produto_unidade_alternativa_demander up ON up.pro_codigo = tp.pro_codigo LEFT JOIN produtos_promocao pp ON pp.pro_codigo = tp.pro_codigo LEFT JOIN empresa_demander ed ON true LEFT JOIN parametro pa ON pa.emp_codigo = ed.emp_codigo ORDER BY tp.pxe_bloqueio DESC);--> statement-breakpoint
