CREATE VIEW "public"."vw_ferias_resumo" AS (WITH anos AS ( SELECT p0.emp_codigo, ano.ano FROM parametro p0 LEFT JOIN LATERAL generate_series(p0.ano_base_controle_ferias::integer + 1, (date_part('year'::text, CURRENT_DATE) + 1::double precision)::integer) ano(ano) ON true ), funcionarios AS ( SELECT f_1.fu_codigo, f_1.fu_tipo, a.ano, ceiling(30::numeric / 365::numeric * datediff('DAY'::character varying, f_1.fu_admissao, f_1.fu_data_demissao)::numeric) AS direito, f_1.fu_data_demissao + '1 day'::interval AS liberado_em, f_1.fu_data_demissao + '1 day'::interval AS limite, f_1.emp_codigo FROM funcionario f_1 JOIN anos a ON a.ano::double precision = date_part('YEAR'::text, f_1.fu_admissao) AND a.emp_codigo = f_1.emp_codigo WHERE f_1.fu_admissao IS NOT NULL AND f_1.fu_tipo = 'C'::bpchar AND f_1.fu_situacao = 2 AND datediff('DAY'::character varying, f_1.fu_admissao, f_1.fu_data_demissao) < 365 UNION ALL SELECT f_1.fu_codigo, f_1.fu_tipo, a.ano, ceiling(30::numeric / 365::numeric * datediff('DAY'::character varying, (((((a.ano::text || '-'::text) || date_part('MONTH'::text, f_1.fu_admissao)::text) || '-'::text) || date_part('DAY'::text, f_1.fu_admissao)::text)::date)::timestamp without time zone, f_1.fu_data_demissao + '1 year'::interval)::numeric) AS direito, LEAST((((((a.ano::text || '-'::text) || date_part('MONTH'::text, f_1.fu_admissao)::text) || '-'::text) || date_part('DAY'::text, f_1.fu_admissao)::text)::date)::timestamp without time zone, f_1.fu_data_demissao) AS liberado_em, LEAST((((((a.ano::text || '-'::text) || date_part('MONTH'::text, f_1.fu_admissao)::text) || '-'::text) || date_part('DAY'::text, f_1.fu_admissao)::text)::date) + '335 days'::interval, f_1.fu_data_demissao) AS limite, f_1.emp_codigo FROM funcionario f_1 JOIN anos a ON (date_part('YEAR'::text, f_1.fu_admissao) + 1::double precision) <= a.ano::double precision AND (date_part('YEAR'::text, f_1.fu_data_demissao) + 1::double precision) >= a.ano::double precision AND a.emp_codigo = f_1.emp_codigo WHERE f_1.fu_admissao IS NOT NULL AND f_1.fu_tipo = 'C'::bpchar AND f_1.fu_situacao = 2 AND datediff('DAY'::character varying, f_1.fu_admissao, f_1.fu_data_demissao) >= 365 UNION ALL SELECT f_1.fu_codigo, f_1.fu_tipo, a.ano, ceiling(30::numeric / 365::numeric * 365::numeric) AS direito, ((((a.ano::text || '-'::text) || date_part('MONTH'::text, f_1.fu_admissao)::text) || '-'::text) || date_part('DAY'::text, f_1.fu_admissao)::text)::date AS liberado_em, ((((((a.ano::text || '-'::text) || date_part('MONTH'::text, f_1.fu_admissao)::text) || '-'::text) || date_part('DAY'::text, f_1.fu_admissao)::text)::date) + '335 days'::interval)::date AS limite, f_1.emp_codigo FROM funcionario f_1 JOIN anos a ON (date_part('YEAR'::text, f_1.fu_admissao) + 1::double precision) <= a.ano::double precision AND a.emp_codigo = f_1.emp_codigo WHERE f_1.fu_admissao IS NOT NULL AND f_1.fu_tipo = 'C'::bpchar AND f_1.fu_situacao <> 2 UNION ALL SELECT f_1.fu_codigo, f_1.fu_tipo, a.ano, ceiling(30::numeric / 365::numeric * 365::numeric) AS direito, ((((a.ano::text || '-'::text) || date_part('MONTH'::text, f_1.fu_inicio_estagio)::text) || '-'::text) || date_part('DAY'::text, f_1.fu_inicio_estagio)::text)::date AS liberado_em, ((((((a.ano::text || '-'::text) || date_part('MONTH'::text, f_1.fu_inicio_estagio)::text) || '-'::text) || date_part('DAY'::text, f_1.fu_inicio_estagio)::text)::date) + '335 days'::interval)::date AS limite, f_1.emp_codigo FROM funcionario f_1 JOIN anos a ON (date_part('YEAR'::text, f_1.fu_inicio_estagio) + 1::double precision) <= a.ano::double precision AND a.emp_codigo = f_1.emp_codigo WHERE f_1.fu_inicio_estagio IS NOT NULL AND f_1.fu_fim_estagio IS NULL AND f_1.fu_tipo = 'E'::bpchar UNION ALL SELECT f_1.fu_codigo, 'E'::bpchar AS fu_tipo, a.ano, ceiling(30::numeric / 365::numeric * datediff('DAY'::character varying, f_1.fu_inicio_estagio, f_1.fu_fim_estagio)::numeric) AS direito, f_1.fu_fim_estagio + '1 day'::interval AS liberado_em, f_1.fu_fim_estagio + '336 days'::interval AS limite, f_1.emp_codigo FROM funcionario f_1 JOIN anos a ON (date_part('YEAR'::text, f_1.fu_inicio_estagio) + 1::double precision) = a.ano::double precision AND a.emp_codigo = f_1.emp_codigo WHERE f_1.fu_inicio_estagio IS NOT NULL AND date_part('YEAR'::text, f_1.fu_fim_estagio) >= a.ano::double precision UNION ALL SELECT f_1.fu_codigo, 'E'::bpchar AS fu_tipo, a.ano, ceiling(30::numeric / 365::numeric * datediff('DAY'::character varying, f_1.fu_inicio_estagio, f_1.fu_fim_estagio)::numeric) AS direito, f_1.fu_fim_estagio + '1 day'::interval AS liberado_em, f_1.fu_data_demissao + '1 day'::interval AS limite, f_1.emp_codigo FROM funcionario f_1 JOIN anos a ON date_part('YEAR'::text, f_1.fu_inicio_estagio) = a.ano::double precision AND a.emp_codigo = f_1.emp_codigo WHERE f_1.fu_situacao = 2 AND date_part('YEAR'::text, f_1.fu_inicio_estagio) = date_part('YEAR'::text, f_1.fu_fim_estagio) AND date_part('YEAR'::text, f_1.fu_admissao) = date_part('YEAR'::text, f_1.fu_data_demissao) UNION ALL SELECT f_1.fu_codigo, f_1.fu_tipo, a.ano, ceiling(30::numeric / 365::numeric * datediff('DAY'::character varying, f_1.fu_inicio_estagio, f_1.fu_fim_estagio)::numeric) AS direito, f_1.fu_fim_estagio + '1 day'::interval AS liberado_em, f_1.fu_fim_estagio + '1 day'::interval AS limite, f_1.emp_codigo FROM funcionario f_1 JOIN anos a ON date_part('YEAR'::text, f_1.fu_inicio_estagio) = a.ano::double precision AND a.emp_codigo = f_1.emp_codigo WHERE f_1.fu_situacao = 2 AND date_part('YEAR'::text, f_1.fu_inicio_estagio) = date_part('YEAR'::text, f_1.fu_fim_estagio) AND f_1.fu_admissao IS NULL AND f_1.fu_data_demissao IS NULL ) SELECT f.ano, f.fu_codigo, f.fu_tipo, iif(f.direito > 30::numeric, 30, f.direito::integer) AS direito, sum(iif(fe.fer_status = 'A'::bpchar, fe.fer_gozo_dias::integer, 0))::integer AS agendado, sum(iif(fe.fer_status = 'P'::bpchar, fe.fer_gozo_dias::integer, 0))::integer AS pre_agendado, sum(iif(fe.fer_tipo = 'C'::bpchar, fe.fer_gozo_dias::integer, 0))::integer AS comprado, sum(iif(fe.fer_tipo = 'T'::bpchar AND fe.fer_status = 'R'::bpchar, fe.fer_gozo_dias::integer, 0))::integer AS tirado, f.liberado_em::date AS liberado_em, f.limite::date AS limite, f.emp_codigo FROM funcionarios f LEFT JOIN ferias fe ON fe.fu_codigo = f.fu_codigo AND "right"(fe.fer_periodo_aquisitivo::text, 4)::integer = f.ano GROUP BY f.ano, f.fu_codigo, f.fu_tipo, f.direito, f.liberado_em, f.limite, f.emp_codigo);--> statement-breakpoint
CREATE VIEW "public"."vw_yzidro_servicos" AS (SELECT '-1'::integer AS codigo, 'PASTA IMAGENS'::text AS nome UNION SELECT '-2'::integer AS codigo, 'PASTA SCHEMAS'::text AS nome UNION SELECT '-3'::integer AS codigo, 'NFSE (TECNOSPEED)'::text AS nome UNION SELECT '-4'::integer AS codigo, 'ACBR'::text AS nome UNION SELECT ys.yzs_codigo AS codigo, ys.yzs_descricao AS nome FROM yzidro_servicos ys ORDER BY 1);--> statement-breakpoint
CREATE VIEW "public"."vw_fluxo_caixa_prev" AS (SELECT cr.cr_vencimento AS data, cr.cb_codigo AS cod_conta, sum(COALESCE(cr.cr_saldo_parcela_mp, 0::numeric))::numeric(18,2) AS receber, 0.00::numeric(18,2) AS pagar, 0.00::numeric(18,2) AS compensar_r, 0.00::numeric(18,2) AS compensar_p, 0.00::numeric(18,2) AS credito, cr.emp_codigo FROM contas_receber cr WHERE cr.cr_vencimento >= CURRENT_DATE GROUP BY cr.cr_vencimento, cr.cb_codigo, cr.emp_codigo UNION SELECT cp.cp_vencimento AS data, cp.cb_codigo AS cod_conta, 0.00::numeric(18,2) AS receber, sum(COALESCE(cp.cp_saldo_mp, 0::numeric))::numeric(18,2) AS pagar, 0.00::numeric(18,2) AS compensar_r, 0.00::numeric(18,2) AS compensar_p, 0.00::numeric(18,2) AS credito, cp.emp_codigo FROM contas_pagar cp WHERE cp.cp_vencimento >= CURRENT_DATE GROUP BY cp.cp_vencimento, cp.cb_codigo, cp.emp_codigo UNION SELECT cx.cx_vencimento AS data, cx.cb_codigo AS cod_conta, 0.00::numeric(18,2) AS receber, 0.00::numeric(18,2) AS pagar, sum(COALESCE(cx.cx_valor_mp, 0::numeric))::numeric(18,2) AS compensar_r, 0.00::numeric(18,2) AS compensar_p, 0.00::numeric(18,2) AS credito, cx.emp_codigo FROM caixa cx, contas c WHERE cx.cx_tipo = 'C'::bpchar AND COALESCE(cx.cx_agrupado, 'N'::bpchar) = 'N'::bpchar AND cx.cx_vencimento > CURRENT_DATE AND cx.cb_codigo = c.cb_codigo AND c.cb_saldo = 0::double precision GROUP BY cx.cx_vencimento, cx.cb_codigo, cx.emp_codigo UNION SELECT cx.cx_vencimento AS data, cx.cb_codigo AS cod_conta, 0.00::numeric(18,2) AS receber, 0.00::numeric(18,2) AS pagar, 0.00::numeric(18,2) AS compensar_r, sum(COALESCE(cx.cx_valor_mp, 0::numeric))::numeric(18,2) AS compensar_p, 0.00::numeric(18,2) AS credito, cx.emp_codigo FROM caixa cx, contas c WHERE cx.cx_tipo = 'D'::bpchar AND COALESCE(cx.cx_agrupado, 'N'::bpchar) = 'N'::bpchar AND cx.cx_vencimento > CURRENT_DATE AND cx.cb_codigo = c.cb_codigo AND c.cb_saldo = 0::double precision GROUP BY cx.cx_vencimento, cx.cb_codigo, cx.emp_codigo UNION SELECT cr.cr_vencimento AS data, NULL::in