CREATE VIEW "public"."vw_fluxo_caixa_prev_anal" AS (SELECT cr.cr_data_emissao AS emissao, cr.cr_vencimento AS vencimento, cr.cb_codigo AS cod_conta, (((cr.ven_cod_pedido || '/'::text) || cr.cr_num_parcela))::character varying(23) AS parcela, cr.cr_codigo AS lancamento, (((c.cli_nome::text || ' - '::text) || c.cli_codigo))::character varying(78) AS cli_for, (((pc.co_estrutura::text || ' - '::text) || pc.co_descricao::text))::character varying(77) AS plano, sum(COALESCE(cr.cr_saldo_parcela_mp, 0::numeric))::numeric(18,2) AS receber, 0.00::numeric(18,2) AS pagar, 0.00::numeric(18,2) AS compensar_r, 0.00::numeric(18,2) AS compensar_p, 0.00::numeric(18,2) AS credito, cr.emp_codigo FROM contas_receber cr LEFT JOIN clientes c ON c.cli_codigo = cr.cli_codigo LEFT JOIN plano_contas pc ON pc.co_codigo = cr.co_codigo WHERE cr.cr_vencimento >= CURRENT_DATE AND cr.cr_saldo_parcela > 0.00 GROUP BY cr.cr_data_emissao, cr.cr_vencimento, cr.cb_codigo, c.cli_nome, c.cli_codigo, cr.ven_cod_pedido, cr.cr_num_parcela, cr.cr_codigo, pc.co_estrutura, pc.co_descricao UNION SELECT cp.cp_data_emissao AS emissao, cp.cp_vencimento AS vencimento, cp.cb_codigo AS cod_conta, (((cp.cmp_codigo || '/'::text) || cp.cp_num_parcela))::character varying(23) AS parcela, cp.cp_codigo AS lancamento, (((f.for_nome::text || ' - '::text) || f.for_codigo))::character varying(78) AS cli_for, (((pc.co_estrutura::text || ' - '::text) || pc.co_descricao::text))::character varying(77) AS plano, 0.00::numeric(18,2) AS receber, sum(COALESCE(cp.cp_saldo_mp, 0::numeric))::numeric(18,2) AS pagar, 0.00::numeric(18,2) AS compensar_r, 0.00::numeric(18,2) AS compensar_p, 0.00::numeric(18,2) AS credito, cp.emp_codigo FROM contas_pagar cp LEFT JOIN fornecedor f ON f.for_codigo = cp.for_codigo LEFT JOIN plano_contas pc ON pc.co_codigo = cp.co_codigo WHERE cp.cp_vencimento >= CURRENT_DATE AND cp.cp_saldo > 0.00 GROUP BY cp.cp_data_emissao, cp.cp_vencimento, cp.cb_codigo, f.for_nome, f.for_codigo, cp.cmp_codigo, cp.cp_num_parcel