CREATE VIEW "public"."vw_pabx" AS (WITH ligacoes AS ( SELECT p.cdr_codigo, p.uniqueid, p.cli_codigo, COALESCE(c.cli_nome, ''::character varying) AS cliente, p.for_codigo, COALESCE(f.for_nome, ''::character varying) AS fornecedor, p.con_codigo, COALESCE(ct.con_nome, ''::character varying) AS contato, CASE WHEN length(p.src::text) = 13 AND "left"(p.src::text, 2) = '00'::text THEN concat('(', substr(p.src::text, 3, 2), ') ', substr(p.src::text, 5, 5), '-', substr(p.src::text, 10, 4))::character varying WHEN length(p.src::text) = 8 THEN concat('(14) ', substr(p.src::text, 1, 4), '-', substr(p.src::text, 5, 4))::character varying WHEN length(p.src::text) = 9 THEN concat('(14) ', substr(p.src::text, 2, 4), '-', substr(p.src::text, 6, 4))::character varying WHEN length(p.src::text) = 10 THEN concat('(', substr(p.src::text, 1, 2), ') ', substr(p.src::text, 3, 4), '-', substr(p.src::text, 7, 4))::character varying WHEN length(p.src::text) = 11 AND i.iyz_tipo = 'FONE_MASTER'::tipo_integracao_yzidro THEN concat('(', substr(p.src::text, 2, 2), ') ', substr(p.src::text, 4, 4), '-', substr(p.src::text, 8, 4))::character varying WHEN length(p.src::text) = 11 AND i.iyz_tipo = '3CX'::tipo_integracao_yzidro THEN concat('(', substr(p.src::text, 1, 2), ') ', substr(p.src::text, 3, 5), '-', substr(p.src::text, 8, 4))::character varying WHEN length(p.src::text) = 12 THEN concat('(', substr(p.src::text, 2, 2), ') ', substr(p.src::text, 4, 5), '-', substr(p.src::text, 9, 4))::character varying WHEN length(p.src::text) = 13 AND i.iyz_tipo = 'FONE_MASTER'::tipo_integracao_yzidro THEN concat('(', substr(p.src::text, 4, 2), ') ', substr(p.src::text, 6, 4), '-', substr(p.src::text, 10, 4))::character varying WHEN length(p.src::text) = 13 AND i.iyz_tipo = '3CX'::tipo_integracao_yzidro THEN concat('(', substr(p.src::text, 3, 2), ') ', substr(p.src::text, 5, 5), '-', substr(p.src::text, 10, 4))::character varying WHEN length(p.src::text) = 14 THEN concat('(', substr(p.src::text, 4, 2), ') ', subst