rquivo, p.iyz_codigo FROM pabx_cdr p JOIN integracoes_yzidro i ON i.iyz_codigo = p.iyz_codigo LEFT JOIN clientes c ON c.cli_codigo = p.cli_codigo LEFT JOIN fornecedor f ON f.for_codigo = p.for_codigo LEFT JOIN contatos ct ON ct.con_codigo = p.con_codigo ) SELECT l.cdr_codigo, l.uniqueid AS id, l.calldate AS data_hora, l.calldate::date AS data, to_char(l.calldate, 'HH24:MI:SS'::text)::character varying(8) AS hora, l.cli_codigo, l.cliente, l.for_codigo, l.fornecedor, l.con_codigo, l.contato, iif(length(l.src::text) < 5 AND length(l.dst::text) < 5, 'INTERNA'::character varying(7), 'EXTERNA'::character varying(7)) AS local, iif(length(l.src::text) = ANY (ARRAY[3, 4]), 'EFETUADA'::character varying(8), 'RECEBIDA'::character varying(8)) AS tipo, CASE WHEN l.disposition::text = 'NO ANSWER'::text OR l.disposition::text = 'ANSWERED'::text AND l.duration < 30 THEN 'NAO ATENDIDO'::character varying WHEN l.disposition::text = 'ANSWERED'::text THEN 'ATENDIDO'::character varying WHEN l.disposition::text = 'BUSY'::text THEN 'OCUPADO'::character varying WHEN l.disposition::text = 'FAILED'::text THEN 'FALHOU'::character varying ELSE l.disposition END::character varying(12) AS status, l.foneorigem AS fone_origem, COALESCE(ro.ram_descricao, l.foneorigem)::character varying(64) AS origem, l.fonedestino AS fone_destino, COALESCE(rd.ram_descricao, l.fonedestino)::character varying(64) AS destino, COALESCE(ro.ram_ramal, rd.ram_ramal, COALESCE(ro.ram_descricao, l.foneorigem), ''::character varying)::character varying(4) AS ramal, COALESCE(ro.ram_descricao, rd.ram_descricao, ''::character varying)::character varying(64) AS atendente, iif(length(l.src::text) = ANY (ARRAY[3, 4]), COALESCE(l.foneorigem, ''::character varying)::character varying(64), COALESCE(l.fonedestino, ''::character varying)::character varying(64)) AS fone_interno, iif(length(l.src::text) = ANY (ARRAY[3, 4]), COALESCE(l.fonedestino, ''::character varying)::character varying(64), COALESCE(l.foneorigem, ''::character varying