CREATE VIEW "public"."vw_unidades_produto" AS (WITH porc_un_alternativas AS ( SELECT unidades_alternativas.pro_codigo, sum(unidades_alternativas.una_porcentual_estoque_demander) AS total FROM unidades_alternativas GROUP BY unidades_alternativas.pro_codigo ) SELECT ((p.pro_codigo::character varying::text || '.'::text) || ua.una_apelido::text)::character varying AS cod_produto, ua.pro_codigo, p.pro_descricao, (iif(pa.exibir_ref_desc_demander = 'Y'::bpchar AND btrim(p.pro_referencia::text) <> ''::text, ('['::text || p.pro_referencia::text) || '] '::text, ''::text) || (((((((p.pro_descricao::text || ' ('::text) || u.un_descricao::text) || ' de '::text) || ua.una_fator::double precision::character varying::text) || ' '::text) || p.pro_unidade::text) || ')'::text))::character varying AS pro_descricao_app, ua.una_apelido AS apelido, u.un_descricao AS unidade, 'UA'::character(2) AS unidade_app, ua.una_fator AS fator_un1, ua.una_fator_un2 AS fator_un2, COALESCE(ua.una_fator_un2, ua.una_fator) AS fator_conversao_app, ua.una_cod_barra AS codigo_barras, ua.una_porcentual_estoque_demander AS porcentual_estoque_demander, iif(p.da > ua.da, p.da, ua.da) AS da, iif(u.un_fracao = 'D'::bpchar, 3, 0) AS decimal_fracao, ua.una_codigo, ua.una_status, btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar AS utiliza_saldo_up, (COALESCE(ua.una_fator_un2, ua.una_fator) * p.pro_qtd_minima_demander)::numeric(18,3) AS qtd_minima, (COALESCE(ua.una_fator_un2, ua.una_fator) * p.pro_qtd_maxima_demander)::numeric(18,3) AS qtd_maxima FROM unidades_alternativas ua JOIN produto p ON ua.pro_codigo = p.pro_codigo JOIN unidade u ON u.un_codigo = ua.un_codigo JOIN parametro pa ON pa.emp_codigo = (( SELECT min(empresa.emp_codigo) AS min FROM empresa WHERE empresa.emp_demander = true)) AND pa.app_tipo_codigo = 'I'::bpchar LEFT JOIN porc_un_alternativas pu ON pu.pro_codigo = p.pro_codigo UNION ALL SELECT iif(pa.app_tipo_codigo = 'B'::bpchar, p.pro_codigo_or, p.pro_codigo::character varying(20)) AS cod_produto, p.pro_codigo, p.pro_descricao, (iif(pa.exibir_ref_desc_demander = 'Y'::bpchar AND btrim(p.pro_referencia::text) <> ''::text, ('['::text || p.pro_referencia::text) || '] '::text, ''::text) || p.pro_descricao::text)::character varying AS pro_descricao_app, iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar, p.pro_unidade, p.pro_segunda_unidade) AS apelido, iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar, p.pro_unidade, p.pro_segunda_unidade) AS unidade, iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text, 'UP'::bpchar, p.pro_unidade_app) AS unidade_app, iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar, 1::numeric(18,3), p.pro_fator_conversao) AS fator_un1, 1::numeric(18,3) AS fator_un2, iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar, 1::numeric(18,3), p.pro_fator_conversao) AS fator_conversao_app, iif(COALESCE(p.pro_codigo_ean, ''::character varying)::text = ''::text, p.pro_codigo_or, p.pro_codigo_ean::character varying(20)) AS codigo_barras, iif(pa.app_tipo_codigo = 'B'::bpchar, NULL::numeric(18,2), (100::numeric - pu.total)::numeric(18,2)) AS porcentual_estoque_demander, p.da, iif(u.un_fracao = 'D'::bpchar, 3, 0) AS decimal_fracao, NULL::integer AS una_codigo, NULL::bpchar AS una_status, btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar AS utiliza_saldo_up, p.pro_qtd_minima_demander AS qtd_minima, p.pro_qtd_maxima_demander AS qtd_maxima FROM produto p JOIN unidade u ON u.un_descricao::text = iif(btrim(COALESCE(p.pro_segunda_unidade, ''::character varying)::text) = ''::text OR p.pro_unidade_app = 'UP'::bpchar, p.pro_unidade, p.pro_segu